def mergetiledem(np.ndarray[DTYPE8_t, ndim=3] tile,np.ndarray[DTYPE8_t, ndim=3] dem):
    #http://ofo.jp/osakana/cgtips/blendmode.phtml
    #softlight 2times
    cdef int xsize = tile.shape[0]
    cdef int ysize = tile.shape[1]
    cdef np.ndarray[DTYPE8_t, ndim=3] a = np.zeros([xsize,ysize,3], dtype=np.uint8)
    cdef int x, y, b, m
    for x in range(xsize):
       for y in range(ysize):
          for b in range(3):
            #soft-light 2times http://ofo.jp/osakana/cgtips/blendmode.phtml
            if 0<dem[x,y,b]<128:
               m= (int)(255*(tile[x,y,b]/255.0)**(2*(1-dem[x,y,b]/255.0)))
            elif dem[x,y,b]>=128:
               m= (int)(255*(tile[x,y,b]/255.0)**(1/(2*dem[x,y,b]/255.0)))
            else:
               m=0
            if 0<tile[x,y,b]<128:
               m = (int)(255*(m/255.0)**(2*(1-tile[x,y,b]/255.0)))
            elif tile[x,y,b]>=128:
               m = (int)(255*(m/255.0)**(1/(2*tile[x,y,b]/255.0)))
            else:
               m = 0
            if tile[x,y,b] == 0:
               a[x,y,b] = 0
            elif m < 5:
               a[x,y,b] = 5
            else:
               a[x,y,b] = m

    return a

def bubble_sort(list data):
    cdef int i
    cdef int j

    sorted_data = data[:]

    for j in range(len(sorted_data), 0, -1):
        for i in range(j - 1):
            if sorted_data[i + 1] < sorted_data[i]:
                tmp = sorted_data[i]
                sorted_data[i] = sorted_data[i + 1]
                sorted_data[i + 1] = tmp

    return sorted_data

def quick_sort(list data, int left, int right):
    cdef int tmp
    cdef int i = left
    cdef int j = right
    cdef int pivot = data[(left + right) // 2]

    while True:
        while data[i] < pivot:
            i += 1
        while pivot < data[j]:
            j -= 1

        if j <= i:
            break

        tmp = data[i]
        data[i] = data[j]
        data[j] = tmp

        i += 1
        j -= 1

    if left < i - 1:
        quick_sort(data, left, i - 1)
    if j + 1 < right:
        quick_sort(data, j + 1, right)

import cython
from cython.parallel import prange


@cython.boundscheck(False)
@cython.wraparound(False)
cpdef double[:, ::1] identity(
        double[:, ::1] A
):
    cdef int m_a = A.shape[0]
    cdef int n_a = A.shape[1]
    cdef int i, j

    if m_a != n_a:
        raise ValueError("A must be a square matrix.")

    for i in prange(m_a, nogil=True):
        for j in prange(n_a):
            if i == j:
                A[i, j] = 1
            else:
                A[i, j] = 0

    return A
